function sesliHarfleriSay(kelime) {
  let sesliHarfler = ["a", "e", "i", "o", "u"];
  let sayac = 0;
  for (let index = 0; index < kelime.length; index++) {
    if (sesliHarfler.includes(kelime[index].toLowerCase())) {
      sayac++;
    }
  }
  return sayac;
}

