function faktoriyelHesapla(sayi) {
  if (sayi === 0 || sayi === 1) {
    return 1;
  }
  let sonuc = 1;
  for (let index = 2; index <= sayi; index++) {
    sonuc *= index;
  }
  return sonuc;
}

let deger = 5;
console.log(deger + "! = " + faktoriyelHesapla(deger));

function terstenSirala(dizi) {
  let yeniDizi = [];
  for (let index = dizi.length - 1; index >= 0; index--) {
    yeniDizi.push(dizi[index]);
  }
  return yeniDizi;
}

let liste = [1, 2, 3, 4, 5];
let tersListe = terstenSirala(liste);
console.log(tersListe);

function palindromKontrol(kelime) {
  let temiz = kelime.toLowerCase();
  let ters = temiz.split("").reverse().join("");
  return temiz === ters;
}

let girdi = "kabak";
let sonuc = palindromKontrol(girdi);
