function tekSayilarinToplami(dizi) {
  let toplam = 0;
  for (let index = 0; index < dizi.length; index++) {
    if (dizi[index] % 2 !== 0) {
      toplam += dizi[index];
    }
  }
  return toplam;
}

let sayilar = [1, 2, 3, 4, 5, 6];
