function asalKontrol(sayi) {
  if (sayi <= 1) return false;
  for (let index = 2; index < sayi; index++) {
    if (sayi % index === 0) {
      return false;
    }
  }
  return true;
}

let deger = 17;
console.log(deger + " asal mi? " + asalKontrol(deger));

function birlestirVeSirala(dizi1, dizi2) {
  let yeniDizi = dizi1.concat(dizi2);
  yeniDizi.sort(function(a, b) {
    return a - b;
  });
  return yeniDizi;
}

let liste1 = [3, 1, 4];
let liste2 = [2, 5, 6];
let siralanmis = birlestirVeSirala(liste1, liste2);
